def p(g):
    L = len(g)
    bars = []
    for c in range(L):
        r = L
        while r and g[r-1][c]:
            r -= 1
        if L - r:
            bars.append((c, L - r))
    if not bars:
        return [[0] * L for _ in g]
    m = min(k for _, k in bars)
    M = max(k for _, k in bars)
    out = [[0] * L for _ in g]
    for c, k in bars:
        v = 2 if k == m else 1 if k == M else 0
        if v:
            for i in range(k):
                out[~i][c] = v
    return out

